const input = $input.first().json;

// Skip sheet update if no row number
if (!input.rowNumber) {
  return [{
    json: {
      ...input,
      sheetUpdates: {},
      skipUpdate: true
    }
  }];
}

const updates = {};

if (input.status_update && input.status_update.trim() !== "") {
  updates["Project Status"] = input.status_update.trim();
}
if (input.next_milestone && input.next_milestone.trim() !== "") {
  updates["Next Milestone"] = input.next_milestone.trim();
}
if (input.key_risks && input.key_risks.trim() !== "") {
  updates["Key Risks"] = input.key_risks.trim();
}
if (input.priority_level && input.priority_level.trim() !== "") {
  updates["Priority Level"] = input.priority_level.trim();
}
if (input.client_intelligence_update && input.client_intelligence_update.trim() !== "") {
  updates["Client Intelligence Summary"] = input.client_intelligence_update.trim();
}
if (input.open_strategic_gaps && input.open_strategic_gaps.trim() !== "") {
  updates["Open Strategic Gaps"] = input.open_strategic_gaps.trim();
}
if (input.email_update && input.email_update.trim() !== "") {
  updates["Email"] = input.email_update.trim();
}
if (input.phone_update && input.phone_update.trim() !== "") {
  updates["Phone"] = input.phone_update.trim();
}
if (input.telegram_username_update && input.telegram_username_update.trim() !== "") {
  updates["Telegram Username"] = input.telegram_username_update.trim();
}

updates["Last Leo Review"] = new Date().toISOString().split('T')[0];

return [{
  json: {
    ...input,
    sheetUpdates: updates,
    rowNumber: input.rowNumber
  }
}];

const aiOutput = $input.first().json || {};
const context = $('Context Builder').first().json || {};

let raw = aiOutput.output || "";
raw = raw.toString().trim();
const start = raw.indexOf('{');
const end = raw.lastIndexOf('}');
const extracted = (start !== -1 && end > start) ? raw.substring(start, end + 1) : "";

let parsed;
try {
  parsed = JSON.parse(extracted);
} catch (e) {
  parsed = {
    needs_clarification: true,
    clarification_question: "Sorry, I had trouble processing that. Please try again.",
    message_type: "text_only",
    case_file: "Unknown",
    telegram_reply_to_client: "Sorry, I encountered a processing error. Please try again.",
    telegram_summary_for_jonathan: "Parse error on last message — please review manually.",
    case_intelligence_update: {},
    action_items: [],
    new_contact_detected: false,
    create_new_client: false,
    new_client_data: {},
    authorize_contact: false,
    authorization_data: {},
    target_chat_id: "",
    target_message: ""
  };
}

// Inject context from Context Builder
parsed.chatId = context.chatId || "";
parsed.isJonathan = context.isJonathan || false;
parsed.isUnknown = context.isUnknown || false;
parsed.fileId = context.fileId || null;
parsed.fileName = context.fileName || null;
parsed.senderId = context.senderId || "";
parsed.senderName = context.senderName || "";
parsed.rawText = context.rawText || "";
parsed.clientRow = context.clientRow || null;
parsed.timestamp = new Date().toISOString();

// Normalize core fields
parsed.message_type = parsed.message_type || context.messageType || "text_only";
parsed.case_file = parsed.case_file || context.caseFile || "Unknown";

// Normalize new fields with safe defaults
parsed.case_intelligence_update = parsed.case_intelligence_update || {};
parsed.case_intelligence_update.current_goals = parsed.case_intelligence_update.current_goals || "";
parsed.case_intelligence_update.next_milestone = parsed.case_intelligence_update.next_milestone || "";
parsed.case_intelligence_update.key_risks = parsed.case_intelligence_update.key_risks || "";
parsed.case_intelligence_update.open_gaps = parsed.case_intelligence_update.open_gaps || "";
parsed.case_intelligence_update.intelligence_summary = parsed.case_intelligence_update.intelligence_summary || "";

parsed.action_items = parsed.action_items || [];
parsed.intelligence_insight = parsed.intelligence_insight || "";

parsed.new_contact_detected = parsed.new_contact_detected || false;
parsed.create_new_client = parsed.create_new_client || false;
parsed.new_client_data = parsed.new_client_data || {};
parsed.new_client_data.name = parsed.new_client_data.name || context.senderName || "";
parsed.new_client_data.telegram_id = parsed.new_client_data.telegram_id || context.senderId || "";
parsed.new_client_data.telegram_username = parsed.new_client_data.telegram_username || context.senderUsername || "";
parsed.new_client_data.phone = parsed.new_client_data.phone || "";
parsed.new_client_data.email = parsed.new_client_data.email || "";
parsed.new_client_data.case_file = parsed.new_client_data.case_file || parsed.case_file || "";
parsed.new_client_data.role = parsed.new_client_data.role || "unknown";
parsed.new_client_data.primary_case_file = parsed.new_client_data.primary_case_file || "";

parsed.authorize_contact = parsed.authorize_contact || false;
parsed.authorization_data = parsed.authorization_data || {};

parsed.needs_clarification = parsed.needs_clarification || false;
parsed.clarification_question = parsed.clarification_question || "";
parsed.create_evidence_bundle = parsed.create_evidence_bundle || false;

parsed.email_update = parsed.email_update || "";
parsed.phone_update = parsed.phone_update || "";
parsed.telegram_username_update = parsed.telegram_username_update || "";
parsed.target_chat_id = parsed.target_chat_id || "";
parsed.target_message = parsed.target_message || "";
parsed.telegram_reply_to_client = parsed.telegram_reply_to_client || "";
parsed.telegram_summary_for_jonathan = parsed.telegram_summary_for_jonathan || "";

return [{ json: parsed }];

const data = $('Parse Agent1').first().json || {};

const safeClientReply = (data.telegram_reply_to_client && data.telegram_reply_to_client.trim() !== "")
  ? data.telegram_reply_to_client
  : !data.rowNumber 
    ? "Hello! I'm LeoLandTek, the Landtek property management assistant. Please share your full name, contact number, and how we can help you today. Someone from our team will follow up shortly."
    : "Thank you. I've noted your message and will process it accordingly.";

const safeJonathanSummary = (data.telegram_summary_for_jonathan && data.telegram_summary_for_jonathan.trim() !== "")
  ? data.telegram_summary_for_jonathan
  : "New message received and processed.";

return [{
  json: {
    ...data,
    telegram_reply_to_client: safeClientReply,
    telegram_summary_for_jonathan: safeJonathanSummary,
    target_chat_id: data.target_chat_id || "",
    target_message: data.target_message || ""
  }
}];

const d = $('Parse Agent1').first().json;

return [{
  json: {
    timestamp: new Date().toISOString(),
    telegramId: d.senderId || "",
    clientName: d.clientRow?.['Name'] || d.senderName || "Unknown",
    company: d.clientRow?.['Company'] || "",
    caseFile: d.case_file || "",
    messageCaption: (d.rawText || "").substring(0, 300),
    fileName: d.fileName || "",
    leoResponse: (d.telegram_summary_for_jonathan || "").substring(0, 300),
    category: d.classification || "",
    strategicPurpose: (d.context_md_content || "").substring(0, 300)
  }
}];

const msg = $('Telegram Trigger').first().json.message || {};
const senderId = msg.from?.id?.toString() || "";
const senderName = [msg.from?.first_name, msg.from?.last_name].filter(Boolean).join(" ") || "Unknown";
const senderUsername = msg.from?.username || "";
const isJonathan = senderId === "6513067717";
const hasFile = !!(msg.document || msg.photo || msg.audio || msg.video || msg.voice);
const messageType = hasFile ? "file" : "text_only";
const rawText = msg.caption || msg.text || "";

// Get client data from Postgres
const clientRow = $input.first().json;
const caseFile = clientRow?.case_file || rawText.match(/[A-Za-z]+-\d{3}/)?.[0] || "Unknown";

// Build recent conversation history
const recentConvs = clientRow?.recent_conversations || [];
const conversationHistory = recentConvs
  .map(r => `[${r.timestamp || ''}] Sender: ${r.message_caption || ''} | Leo: ${r.leo_response || ''}`)
  .join('\n');

// Build client profile
const clientProfile = clientRow?.name ? `Client Name: ${clientRow.name || ""}
Company: ${clientRow.company || ""}
Case File: ${clientRow.case_file || ""}
Status: ${clientRow.status || ""}
Instructions: ${clientRow.instructions || ""}
Current Goals: ${clientRow.current_goals || ""}
Project Status: ${clientRow.project_status || ""}
Next Milestone: ${clientRow.next_milestone || ""}
Key Risks: ${clientRow.key_risks || ""}
Priority: ${clientRow.priority_level || ""}
Email: ${clientRow.email || ""}
Phone: ${clientRow.phone || ""}
Telegram Username: ${clientRow.telegram_username || ""}
Legal Folder Path: ${clientRow.legal_folder_path || ""}
Finance Folder Path: ${clientRow.finance_folder_path || ""}
Project Folder Path: ${clientRow.project_folder_path || ""}
Client Intelligence Summary: ${clientRow.client_intelligence_summary || ""}
Open Strategic Gaps: ${clientRow.open_strategic_gaps || ""}`
: "No matching client profile found.";

// Build file info
let fileInfo = "No file attached.";
if (hasFile) {
  const doc = msg.document || {};
  const photo = msg.photo?.[msg.photo.length - 1] || {};
  fileInfo = `File type: ${msg.document ? "document" : msg.photo ? "photo" : "other"}
Original filename: ${doc.file_name || "unnamed"}
MIME type: ${doc.mime_type || "unknown"}
File size: ${doc.file_size || photo.file_size || "unknown"} bytes`;
}

const agentInput = `SENDER:
Name: ${senderName}
Telegram ID: ${senderId}
Telegram Username: ${senderUsername}
Is Jonathan (owner): ${isJonathan}

MESSAGE TYPE: ${messageType}
TIMESTAMP: ${new Date().toISOString()}

RAW MESSAGE / CAPTION:
${rawText || "(no text provided)"}

FILE INFO:
${fileInfo}

CLIENT PROFILE:
${clientProfile}

RECENT CONVERSATION HISTORY (last 4):
${conversationHistory || "No previous conversations"}`;

return [{
  json: {
    agentInput,
    messageType,
    isJonathan,
    senderId,
    senderName,
    senderUsername,
    caseFile,
    clientRow,
    rawText,
    hasFile,
    fileId: hasFile ? (msg.document?.file_id || msg.photo?.[msg.photo.length-1]?.file_id || null) : null,
    fileName: msg.document?.file_name || null,
    chatId: msg.chat?.id?.toString() || ""
  }
}];

const parsed = $('Parse Agent1').first().json;
const items = parsed.action_items || [];
const caseFile = parsed.case_file || 'Unknown';

if (!items.length) return [{ json: { skip: true } }];

return items.map(item => ({
  json: {
    case_file: caseFile,
    description: item.description || '',
    due_date: item.due_date || null,
    priority: item.priority || 'Medium',
    created_by: 'Leo'
  }
}));

// Resolve Drive folder ID based on case_file + classification
const caseFile = $('Parse Agent1').first().json.case_file;
const classification = $('Parse Agent1').first().json.classification;

// Default inbox for Owner / unknown / unmapped cases
const FALLBACK = '142QmpKv2DvWjJ46nhOq_C8HhN6xD4Zjy';

const folders = {
  'Paracale-001': {
    'Legal':    '1TKMNbNxnns0FdtEuvEPMLISnnmmy46jx',
    'Finance':  '1qbKEeoj9yv-OcxxodAH9ec_oAwPkps_r',
    'Evidence': '1EHYKQJxOZTxDxB5BliyuC0fvq5M2Tmhe',
    'default':  '1TKMNbNxnns0FdtEuvEPMLISnnmmy46jx'  // Legal as default for Paracale-001
  },
  'MWK-001': {
    'Legal':    '1y3w8gIS8SG66J2npfKhKQibOUpqwUTUi',
    'Finance':  '1-LlWNPW7rzVYFsz_7gFl0cMjlA9kw1F0',
    'Evidence': '176U9wV-8jsCtDp0hCuj-hff2J6h0BrEs',
    'default':  '1y3w8gIS8SG66J2npfKhKQibOUpqwUTUi'  // Legal as default for MWK-001
  }
};

// If case is Owner, unknown, empty, or not in our map → fallback inbox
const caseFolders = folders[caseFile];
let folderId;
if (!caseFolders || caseFile === 'Owner' || !caseFile) {
  folderId = FALLBACK;
} else {
  folderId = caseFolders[classification] || caseFolders['default'];
}

const input = $input.first();
return [{
  json: {
    ...input.json,
    drive_folder_id: folderId,
    drive_folder_case: caseFile || 'unknown',
    drive_folder_classification: classification || 'unknown',
    drive_folder_routed_to_fallback: folderId === FALLBACK
  },
  binary: input.binary
}];
